// Unit 24. El Mundo Laboral
// Work Culture & Formal Register

export default {n:24,lang:"es",srcLang:"en",track:"v2",title:"El Mundo Laboral",sub:"Work Culture & Formal Register",icon:"💼",level:"B1.4",color:"#7B5EE8",lessons:[
  {id:"esp24l1",title:"En la oficina",icon:"🏢",xp:20,board:true,steps:[
        {type:"intro",title:"En la oficina",desc:"Learn the essential vocabulary of the working world: jobs, companies, and colleagues.",goals:["Name workplaces and job roles","Describe your work situation","Use work vocabulary in context"]},
        {type:"teach",trg:"el trabajo",src:"work / job",pos:"verb",gender:null,phonetic:"tra-BA-ho",note:"Both the noun (el trabajo) and verb (trabajar) share this root.",example:"A: ¿Te gusta tu trabajo?\nB: Sí, me encanta. Trabajo en una empresa de tecnología.\nA: ¿Cuántas horas trabajas al día?\nB: Normalmente ocho horas, de nueve a cinco.",exampleSrc:"A: Do you like your job?\nB: Yes, I love it. I work at a tech company.\nA: How many hours do you work per day?\nB: Normally eight hours, from nine to five.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"el empleo",src:"employment / position",pos:"noun",gender:"m",phonetic:"em-PLEH-o",note:"More formal than trabajo. Often used in job listings and official contexts.",example:"A: Estoy buscando empleo desde hace dos meses.\nB: ¿Has probado las páginas de empleo en internet?\nA: Sí, ya he enviado diez solicitudes.\nB: Muy bien. Algo saldrá pronto.",exampleSrc:"A: I have been looking for employment for two months.\nB: Have you tried the job websites on the internet?\nA: Yes, I have already sent ten applications.\nB: Very good. Something will come up soon.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la empresa",src:"the company",pos:"noun",gender:"f",phonetic:"em-PREH-sa",note:"La empresa is feminine. Related: el empresario (entrepreneur).",example:"A: ¿En qué empresa trabajas?\nB: Trabajo en una empresa de marketing.\nA: ¿Es grande o pequeña?\nB: Es mediana, tiene unos cien empleados.",exampleSrc:"A: What company do you work at?\nB: I work at a marketing company.\nA: Is it large or small?\nB: It is medium-sized, it has about a hundred employees.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"la oficina",src:"the office",pos:"noun",gender:"f",phonetic:"o-fee-SEE-na",note:"Cognate with English 'office'. La oficina is feminine.",example:"A: ¿Dónde está tu oficina?\nB: Está en el centro de la ciudad.\nA: ¿Vas en coche o en metro?\nB: Normalmente voy en metro porque es más rápido.",exampleSrc:"A: Where is your office?\nB: It is in the city center.\nA: Do you go by car or by metro?\nB: I normally go by metro because it is faster.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el jefe",src:"the boss (male)",pos:"noun",gender:"m",phonetic:"HEH-feh",note:"La jefa for a female boss. Both are common in modern workplaces.",example:"A: ¿Cómo es tu jefe?\nB: Es muy exigente, pero justo.\nA: ¿Tiene mucha experiencia?\nB: Sí, lleva veinte años en la empresa.",exampleSrc:"A: What is your boss like?\nB: He is very demanding, but fair.\nA: Does he have a lot of experience?\nB: Yes, he has been at the company for twenty years.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el compañero",src:"the colleague (male)",pos:"noun",gender:"m",phonetic:"kom-pa-NYEH-ro",note:"La compañera for female. Compañero de trabajo = work colleague.",example:"A: ¿Te llevas bien con tus compañeros?\nB: Sí, son muy amables y colaboradores.\nA: ¿Almuerzan juntos?\nB: A veces comemos juntos en la cafetería.",exampleSrc:"A: Do you get along with your colleagues?\nB: Yes, they are very kind and collaborative.\nA: Do you have lunch together?\nB: Sometimes we eat together in the cafeteria.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la reunión",src:"the meeting",pos:"noun",gender:"f",phonetic:"reh-oo-NYON",note:"From reunir (to gather). Tener una reunión = to have a meeting.",example:"A: ¿A qué hora es la reunión?\nB: A las diez en la sala de conferencias.\nA: ¿Quién va a presentar el informe?\nB: Creo que lo presenta el jefe de ventas.",exampleSrc:"A: What time is the meeting?\nB: At ten in the conference room.\nA: Who is going to present the report?\nB: I think the head of sales is presenting it.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"tip",title:"Work vocabulary patterns",text:"Many work words form natural pairs:\n\nel jefe / la jefa (boss m/f)\nel compañero / la compañera (colleague m/f)\nel empleado / la empleada (employee m/f)\nel empresario / la empresaria (entrepreneur m/f)\n\nThe -o/-a ending switches gender consistently.",icon:"💡"},
        {type:"mc",q:"Tu amigo busca un puesto nuevo. Dices: 'Espero que encuentres un buen ___.'",opts:["empleo","oficina","jefe","reunión"],ans:"empleo",hint:"The word that means 'position' or 'employment' fits here."},
        {type:"mc",q:"'Tenemos una ___ a las tres de la tarde con el equipo de ventas.'",opts:["empresa","reunión","oficina","empleo"],ans:"reunión",hint:"A scheduled gathering with the sales team."},
        {type:"fb",opts:["jefe","reunión","empresa","oficina"],hint:"The person who leads and supervises your work.",s:"Mi {1} es muy exigente, pero aprendo mucho.",a:"jefe"},
        {type:"match",pairs:[{trg:"el trabajo",src:"work / job"},{trg:"la empresa",src:"the company"},{trg:"el jefe",src:"the boss"},{trg:"la reunión",src:"the meeting"},{trg:"el compañero",src:"the colleague"}]},
        {type:"mc",q:"'Trabajo en una ___ de tecnología con doscientos empleados.'",opts:["reunión","oficina","empresa","empleo"],ans:"empresa",hint:"The organization or business where many people work together."},
        {type:"fb",opts:["compañeros","jefes","oficinas","empresas"],hint:"The people who work alongside you every day.",s:"Mis {1} de trabajo son muy simpáticos.",a:"compañeros"},
        {type:"mc",q:"¿Dónde trabaja Ana? 'Ana trabaja en una ___ en el centro.'",opts:["reunión","empleo","jefe","oficina"],ans:"oficina",hint:"The physical place where she sits and works daily."},
        {type:"mc",q:"Which pair correctly shows the feminine form?",opts:["el jefe / la jefa","el jefe / la jefe","el compañero / la compañera de","el reunión / la reunión"],ans:"el jefe / la jefa",hint:"The standard -o to -a pattern applies to boss as well."},
        {type:"drag_fill",hint:"A meeting, your boss, and colleagues from the department.",s:"Mañana tengo una {1} con mi {2} y tres {3} del departamento.",blanks:{"1":"reunión","2":"jefe","3":"compañeros"},pool:["reunión","jefe","compañeros","empresa","empleo","oficina"]}
  ]},
  {id:"esp24l2",title:"Buscar trabajo",icon:"📋",xp:20,board:true,steps:[
        {type:"intro",title:"Buscar trabajo",desc:"Expand your work vocabulary with terms for salary, experience, hiring, and interviews.",goals:["Talk about salaries and experience","Use hiring and interview vocabulary","Describe job-seeking activities"]},
        {type:"teach",trg:"el sueldo",src:"the salary",pos:"noun",gender:"m",phonetic:"SWEL-do",note:"El sueldo is masculine. Un aumento de sueldo = a pay raise.",example:"A: ¿Estás contento con tu sueldo?\nB: No mucho. Voy a pedir un aumento.\nA: ¿Cuándo fue tu último aumento?\nB: Hace dos años. Ya es hora de otro.",exampleSrc:"A: Are you happy with your salary?\nB: Not much. I am going to ask for a raise.\nA: When was your last raise?\nB: Two years ago. It is time for another one.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la experiencia",src:"experience",pos:"noun",gender:"f",phonetic:"eks-peh-RYEN-sya",note:"Cognate with English. Tener experiencia en = to have experience in.",example:"A: ¿Cuántos años de experiencia tienes?\nB: Tengo cinco años en marketing digital.\nA: Eso es muy valioso hoy en día.\nB: Sí, la experiencia práctica es esencial.",exampleSrc:"A: How many years of experience do you have?\nB: I have five years in digital marketing.\nA: That is very valuable nowadays.\nB: Yes, practical experience is essential.",funFact:"Cognate with English 'experience'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el puesto",src:"the position / post",pos:"noun",gender:"m",phonetic:"PWES-to",note:"El puesto de trabajo = the job position. More specific than empleo.",example:"A: ¿Para qué puesto estás buscando?\nB: Para el puesto de gerente de proyectos.\nA: ¿Tienes la experiencia necesaria?\nB: Sí, he gestionado varios proyectos grandes.",exampleSrc:"A: What position are you looking for?\nB: For the project manager position.\nA: Do you have the necessary experience?\nB: Yes, I have managed several large projects.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el currículum",src:"the CV / resume",pos:"noun",gender:"m",phonetic:"koo-RREE-koo-lum",note:"Also called hoja de vida in Latin America. Enviar el currículum = to send one's CV.",example:"A: ¿Ya enviaste tu currículum?\nB: Sí, lo envié ayer por correo electrónico.\nA: ¿Incluiste tu experiencia más reciente?\nB: Claro, y también mis referencias.",exampleSrc:"A: Did you already send your CV?\nB: Yes, I sent it yesterday by email.\nA: Did you include your most recent experience?\nB: Of course, and also my references.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la entrevista",src:"the interview",pos:"verb",gender:null,phonetic:"en-treh-VEES-ta",note:"Entrevista de trabajo = job interview. The verb is entrevistar.",example:"A: Tengo una entrevista de trabajo mañana.\nB: ¡Qué bien! ¿Para qué empresa?\nA: Para una empresa de consultoría.\nB: Te deseo mucha suerte.",exampleSrc:"A: I have a job interview tomorrow.\nB: Great! For which company?\nA: For a consulting company.\nB: I wish you lots of luck.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"teach",trg:"contratar",src:"to hire",pos:"verb",gender:null,phonetic:"kon-tra-TAR",note:"El contrato = the contract. Contratar a alguien = to hire someone.",example:"A: ¿Cuántas personas van a contratar?\nB: Necesitamos contratar a tres ingenieros.\nA: ¿Cuándo empiezan las entrevistas?\nB: La semana que viene.",exampleSrc:"A: How many people are they going to hire?\nB: We need to hire three engineers.\nA: When do the interviews start?\nB: Next week.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"despedir",src:"to fire / to let go",pos:"verb",gender:null,phonetic:"des-peh-DEER",note:"Despedir also means 'to say goodbye'. Context makes the meaning clear.",example:"A: ¿Supiste que despidieron a Carlos?\nB: No, ¿por qué lo despidieron?\nA: Parece que la empresa recortó personal.\nB: Qué lástima. Era un buen compañero.",exampleSrc:"A: Did you hear they fired Carlos?\nB: No, why did they fire him?\nA: It seems the company cut staff.\nB: What a shame. He was a good colleague.",funFact:"A -ir verb. Similar conjugation to -er verbs with a few differences."},
        {type:"tip",title:"The hiring cycle",text:"The job search process in Spanish:\n\nbuscar empleo (look for work)\nenviar el currículum (send the CV)\ntener una entrevista (have an interview)\nser contratado (be hired)\nser despedido (be fired/let go)\n\nAll use ser for the passive voice forms.",icon:"💡"},
        {type:"mc",q:"María acaba de terminar la universidad. No tiene mucha ___.",opts:["experiencia","reunión","oficina","sueldo"],ans:"experiencia",hint:"What recent graduates typically lack in the job market."},
        {type:"mc",q:"'La empresa va a ___ a diez personas nuevas este mes.'",opts:["despedir","contratar","entrevistar","buscar"],ans:"contratar",hint:"The company is bringing new people in, not letting them go."},
        {type:"fb",opts:["entrevista","reunión","empresa","experiencia"],hint:"A formal meeting where they evaluate you for a position.",s:"Tengo una {1} de trabajo el viernes a las diez.",a:"entrevista"},
        {type:"match",pairs:[{trg:"el sueldo",src:"the salary"},{trg:"el puesto",src:"the position"},{trg:"el currículum",src:"the CV"},{trg:"contratar",src:"to hire"},{trg:"despedir",src:"to fire"}]},
        {type:"mc",q:"Pedro no está contento con su ___. Quiere ganar más dinero.",opts:["puesto","currículum","sueldo","entrevista"],ans:"sueldo",hint:"The thing that determines how much money you earn each month."},
        {type:"fb",opts:["currículum","entrevista","sueldo","puesto"],hint:"The document that lists your education and work history.",s:"Envié mi {1} a tres empresas diferentes.",a:"currículum"},
        {type:"mc",q:"'La empresa tuvo que ___ a veinte empleados por la crisis.'",opts:["contratar","buscar","entrevistar","despedir"],ans:"despedir",hint:"The opposite of hiring. Letting employees go due to the crisis."},
        {type:"drag_fill",hint:"A position, good pay, and good work experience.",s:"Busco un {1} con buen {2} y buena {3} laboral.",blanks:{"1":"puesto","2":"sueldo","3":"experiencia"},pool:["puesto","sueldo","experiencia","entrevista","empresa","currículum"]},
        {type:"mc",q:"Which word means both 'to fire' and 'to say goodbye'?",opts:["despedir","contratar","trabajar","entrevistar"],ans:"despedir",hint:"This verb has two very different meanings depending on context."}
  ]},
  {id:"esp24l3",title:"El registro formal",icon:"📝",xp:20,board:true,steps:[
        {type:"intro",title:"El registro formal",desc:"Master the formal expressions used in professional written and spoken Spanish.",goals:["Use formal greetings and closings","Write with usted consistently","Express gratitude and availability formally"]},
        {type:"teach",trg:"Estimado/a",src:"Dear (formal)",pos:"noun",gender:null,phonetic:"es-tee-MA-do / es-tee-MA-da",note:"The standard opening for formal letters. Matches the gender of the recipient.",example:"A: ¿Cómo empiezo la carta formal?\nB: Empieza con 'Estimado señor' o 'Estimada señora'.\nA: ¿Y si no sé el nombre?\nB: Puedes escribir 'Estimado/a señor/a'.",exampleSrc:"A: How do I start the formal letter?\nB: Start with 'Dear sir' or 'Dear madam'.\nA: And if I don't know the name?\nB: You can write 'Dear sir/madam'.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"Le agradezco",src:"I thank you (formal)",pos:"intj",gender:null,phonetic:"leh a-gra-DES-ko",note:"Le = formal 'you' (indirect object). Much more formal than simply 'gracias'.",example:"A: Le agradezco su rápida respuesta.\nB: No hay de qué. Estoy a su disposición.\nA: Le agradezco también la información adicional.\nB: Con mucho gusto.",exampleSrc:"A: I thank you for your quick response.\nB: You're welcome. I am at your disposal.\nA: I also thank you for the additional information.\nB: With pleasure.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Le escribo para",src:"I am writing to you to",pos:"noun",gender:null,phonetic:"leh es-KREE-bo PA-ra",note:"Standard opening for formal letters stating the purpose.",example:"A: Le escribo para solicitar información sobre el puesto.\nB: Con gusto le envío los detalles.\nA: Le agradezco su amabilidad.\nB: Quedo a su disposición para cualquier consulta.",exampleSrc:"A: I am writing to you to request information about the position.\nB: I will gladly send you the details.\nA: I thank you for your kindness.\nB: I remain at your disposal for any inquiry.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"Atentamente",src:"Sincerely / Yours faithfully",pos:"noun",gender:null,phonetic:"a-TEN-ta-MEN-teh",note:"The most common formal letter closing. Place it before your name.",example:"A: ¿Cómo termino una carta formal?\nB: Usa 'Atentamente' antes de tu firma.\nA: ¿Hay otras opciones?\nB: También puedes usar 'Cordialmente' o 'Un cordial saludo'.",exampleSrc:"A: How do I end a formal letter?\nB: Use 'Sincerely' before your signature.\nA: Are there other options?\nB: You can also use 'Cordially' or 'Kind regards'.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"Quedo a su disposición",src:"I remain at your disposal",pos:"intj",gender:null,phonetic:"KEH-do a soo dis-po-see-SYON",note:"A professional closing phrase showing availability and willingness to help.",example:"A: Para cualquier pregunta, quedo a su disposición.\nB: Muchas gracias. Le escribiré si tengo dudas.\nA: No dude en escribirme cuando lo necesite.\nB: Muy amable de su parte.",exampleSrc:"A: For any questions, I remain at your disposal.\nB: Thank you very much. I will write to you if I have doubts.\nA: Do not hesitate to write to me when you need to.\nB: Very kind of you.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Cordialmente",src:"Cordially / Kind regards",pos:"noun",gender:null,phonetic:"kor-dyal-MEN-teh",note:"Slightly less formal than Atentamente but still appropriate for business.",example:"A: ¿Qué cierre uso si no conozco bien al destinatario?\nB: 'Cordialmente' es una buena opción.\nA: ¿Es menos formal que 'Atentamente'?\nB: Un poco, pero sigue siendo profesional.",exampleSrc:"A: What closing do I use if I don't know the recipient well?\nB: 'Cordially' is a good option.\nA: Is it less formal than 'Sincerely'?\nB: A little, but it is still professional.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"tip",title:"Formal letter structure",text:"A Spanish formal letter follows this structure:\n\nEstimado/a + name (Dear...)\nLe escribo para + purpose\nBody paragraphs with usted/su\nQuedo a su disposición (optional)\nAtentamente / Cordialmente\nYour name",icon:"💡"},
        {type:"mc",q:"Para empezar una carta formal a una mujer, escribes:",opts:["Estimada señora","Estimado señora","Hola señora","Querido señora"],ans:"Estimada señora",hint:"The greeting must match the feminine gender of the recipient."},
        {type:"mc",q:"'___ su atención y tiempo dedicado a mi solicitud.'",opts:["Gracias por","Le agradezco","Te agradezco","Agradecemos"],ans:"Le agradezco",hint:"The formal singular form with the indirect object pronoun for usted."},
        {type:"fb",opts:["escribo","agradezco","envío","respondo"],hint:"The verb that means 'I write' comes after the formal opening.",s:"Le {1} para solicitar información sobre el puesto de gerente.",a:"escribo"},
        {type:"match",pairs:[
          {trg:"Estimado/a",src:"Dear (formal)"},
          {trg:"Le agradezco",src:"I thank you (formal)"},
          {trg:"Atentamente",src:"Sincerely"},
          {trg:"Cordialmente",src:"Kind regards"},
          {trg:"Quedo a su disposición",src:"I remain at your disposal"}
        ]},
        {type:"mc",q:"¿Qué frase cierra una carta formal mostrando disponibilidad?",opts:["Hasta luego","Muchas gracias","Quedo a su disposición","Nos vemos"],ans:"Quedo a su disposición",hint:"This phrase tells the reader you are available for further contact."},
        {type:"fb",opts:["Estimado","Querido","Hola","Bueno"],hint:"The formal letter opening that means 'Dear' in professional contexts.",s:"{1}, le escribo para expresar mi interés en el puesto.",a:"Estimado"},
        {type:"mc",q:"To end a very formal business letter, you write:",opts:["Chao","Hasta pronto","Nos vemos","Atentamente"],ans:"Atentamente",hint:"The most formal and standard letter closing in Spanish."},
        {type:"drag_fill",hint:"A formal letter: opening, purpose statement, and closing.",s:"{1} señor López, {2} para informarle sobre nuestra decisión. {3}, María García.",blanks:{"1":"Estimado","2":"Le escribo","3":"Atentamente"},pool:["Estimado","Le escribo","Atentamente","Hola","Te escribo","Chao"]},
        {type:"mc",q:"Which phrase would NOT appear in a formal business letter?",opts:["¡Hola, qué tal!","Quedo a su disposición","Le agradezco su tiempo","Estimada señora Ruiz"],ans:"¡Hola, qué tal!",hint:"One of these is far too casual for a professional letter."},
        {type:"fb",opts:["disposición","opinión","reunión","empresa"],hint:"The noun that means 'disposal' or 'availability' in this formal phrase.",s:"Quedo a su {1} para cualquier consulta adicional.",a:"disposición"}
  ]},
  {id:"esp24l4",title:"La carta de presentación",icon:"✉️",xp:20,board:true,steps:[
        {type:"intro",title:"La carta de presentación",desc:"Learn to write a cover letter in Spanish, expressing your qualifications and motivation.",goals:["Structure a cover letter properly","Express qualifications and motivation","Use formal connecting phrases"]},
        {type:"teach",trg:"la carta de presentación",src:"cover letter",pos:"noun",gender:"f",phonetic:"KAR-ta deh preh-sen-ta-SYON",note:"Always accompanies the currículum when applying for jobs in Spanish-speaking countries.",example:"A: ¿Necesito enviar una carta de presentación?\nB: Sí, es imprescindible para este puesto.\nA: ¿Qué incluyo en la carta?\nB: Tu motivación, experiencia y por qué eres ideal para el puesto.",exampleSrc:"A: Do I need to send a cover letter?\nB: Yes, it is essential for this position.\nA: What do I include in the letter?\nB: Your motivation, experience, and why you are ideal for the position.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"Me dirijo a usted para",src:"I am addressing you in order to",pos:"intj",gender:null,phonetic:"meh dee-REE-ho a oos-TED PA-ra",note:"Very formal opening. Alternative to 'Le escribo para' with a slightly more respectful tone.",example:"A: Me dirijo a usted para expresar mi interés en el puesto de analista.\nB: Gracias por su interés en nuestra empresa.\nA: He visto la oferta en su página web.\nB: Sí, buscamos candidatos con experiencia.",exampleSrc:"A: I am addressing you to express my interest in the analyst position.\nB: Thank you for your interest in our company.\nA: I saw the listing on your website.\nB: Yes, we are looking for candidates with experience.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Cuento con experiencia en",src:"I have experience in",pos:"intj",gender:null,phonetic:"KWEN-to kon eks-peh-RYEN-sya en",note:"Contar con = to have, to count on. Formal way to present qualifications.",example:"A: ¿Qué experiencia tiene usted?\nB: Cuento con experiencia en gestión de proyectos.\nA: ¿Cuántos años?\nB: Cuento con más de cinco años en el sector.",exampleSrc:"A: What experience do you have?\nB: I have experience in project management.\nA: How many years?\nB: I have more than five years in the sector.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Considero que puedo aportar",src:"I believe I can contribute",pos:"intj",gender:null,phonetic:"kon-SEE-deh-ro keh PWEH-do a-por-TAR",note:"Aportar = to contribute, to bring value. Strong phrase for cover letters.",example:"A: ¿Por qué debemos contratarle?\nB: Considero que puedo aportar ideas innovadoras.\nA: ¿Qué más puede ofrecer al equipo?\nB: También puedo aportar mi experiencia internacional.",exampleSrc:"A: Why should we hire you?\nB: I believe I can contribute innovative ideas.\nA: What else can you offer the team?\nB: I can also contribute my international experience.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Adjunto mi currículum",src:"I attach my CV",pos:"adj",gender:null,phonetic:"ad-HOON-to mee koo-RREE-koo-lum",note:"Adjuntar = to attach. Essential phrase for email applications.",example:"A: ¿Has adjuntado todos los documentos?\nB: Sí, adjunto mi currículum y mis certificados.\nA: No olvides incluir tus referencias.\nB: Cierto, las incluyo en el correo.",exampleSrc:"A: Have you attached all the documents?\nB: Yes, I attach my CV and my certificates.\nA: Don't forget to include your references.\nB: True, I'll include them in the email.",funFact:"Spanish adjectives agree in gender and number. Most change -o/-a for gender and add -s for plural."},
        {type:"teach",trg:"Quedo a la espera de su respuesta",src:"I await your response",pos:"intj",gender:null,phonetic:"KEH-do a la es-PEH-ra deh soo res-PWES-ta",note:"Standard closing before 'Atentamente'. Shows professional patience.",example:"A: ¿Cómo termino la carta de presentación?\nB: Escribe 'Quedo a la espera de su respuesta'.\nA: ¿Es mejor que 'Espero su respuesta'?\nB: Sí, es más formal y profesional.",exampleSrc:"A: How do I end the cover letter?\nB: Write 'I await your response'.\nA: Is it better than 'I hope for your response'?\nB: Yes, it is more formal and professional.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Cover letter template",text:"A standard carta de presentación:\n\n1. Estimado/a + name\n2. Me dirijo a usted para expresar mi interés en...\n3. Cuento con experiencia en...\n4. Considero que puedo aportar...\n5. Adjunto mi currículum para su consideración.\n6. Quedo a la espera de su respuesta.\n7. Atentamente, [name]",icon:"💡"},
        {type:"mc",q:"Para presentar tus cualificaciones formalmente, dices:",opts:["Cuento con experiencia en marketing","Tengo mucho trabajo","Mi jefe es bueno","Me gusta la oficina"],ans:"Cuento con experiencia en marketing",hint:"The phrase that formally presents what professional background you have."},
        {type:"mc",q:"'___ mi currículum para su consideración.' Completa:",opts:["Envío","Adjunto","Escribo","Presento"],ans:"Adjunto",hint:"The formal verb meaning to attach a document."},
        {type:"fb",opts:["Considero","Creo","Pienso","Digo"],hint:"The most formal way to express 'I believe' in a cover letter.",s:"{1} que puedo aportar valor a su equipo.",a:"Considero"},
        {type:"mc",q:"Which phrase is the most formal way to open a cover letter?",opts:["Hola, le escribo porque","Te cuento que quiero","Me dirijo a usted para","Oye, necesito trabajo"],ans:"Me dirijo a usted para",hint:"The phrase using dirigirse with the formal 'you' pronoun."},
        {type:"fb",opts:["espera","vista","mano","parte"],hint:"This noun means 'waiting' or 'expectation'.",s:"Quedo a la {1} de su respuesta.",a:"espera"},
        {type:"match",pairs:[
          {trg:"Carta de presentación",src:"Cover letter"},
          {trg:"Cuento con experiencia",src:"I have experience"},
          {trg:"Adjunto mi currículum",src:"I attach my CV"},
          {trg:"Me dirijo a usted",src:"I address you"},
          {trg:"Quedo a la espera",src:"I await"}
        ]},
        {type:"mc",q:"After describing your qualifications, you write: 'Considero que puedo ___ ideas nuevas al equipo.'",opts:["contratar","escribir","buscar","aportar"],ans:"aportar",hint:"The verb meaning 'to contribute' or 'to bring value'."},
        {type:"drag_fill",hint:"Addressing, presenting experience, and attaching documents.",s:"{1} a usted para expresar mi interés. {2} con tres años de experiencia. {3} mi currículum.",blanks:{"1":"Me dirijo","2":"Cuento","3":"Adjunto"},pool:["Me dirijo","Cuento","Adjunto","Le escribo","Tengo","Envío"]},
        {type:"mc",q:"Which sentence would close a cover letter BEFORE 'Atentamente'?",opts:["Quedo a la espera de su respuesta","¡Nos vemos pronto!","Chao, hasta luego","Gracias, adiós"],ans:"Quedo a la espera de su respuesta",hint:"The formal phrase that expresses you are waiting for their reply."},
        {type:"fb",opts:["Considero","Cuento","Adjunto","Escribo"],hint:"The formal verb meaning 'I believe' used to express what you can offer.",s:"{1} que puedo aportar creatividad y dedicación a su equipo.",a:"Considero"}
  ]},
  {id:"esp24l5",title:"La entrevista de trabajo",icon:"🤝",xp:20,board:true,steps:[
        {type:"intro",title:"La entrevista de trabajo",desc:"Practice the vocabulary and phrases used in Spanish job interviews.",goals:["Answer common interview questions","Describe strengths and weaknesses","Use formal self-presentation phrases"]},
        {type:"teach",trg:"Hábleme de usted",src:"Tell me about yourself",pos:"intj",gender:null,phonetic:"AH-bleh-meh deh oos-TED",note:"The classic opening question in Spanish interviews. Uses usted (formal).",example:"A: Hábleme de usted.\nB: Soy ingeniera con cinco años de experiencia en proyectos internacionales.\nA: ¿Qué la motiva en su trabajo?\nB: Me motiva resolver problemas y trabajar en equipo.",exampleSrc:"A: Tell me about yourself.\nB: I am an engineer with five years of experience in international projects.\nA: What motivates you in your work?\nB: Solving problems and working as a team motivates me.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"¿Por qué quiere este puesto?",src:"Why do you want this position?",pos:"intj",gender:null,phonetic:"por KEH KYEH-reh ES-teh PWES-to",note:"Prepare this answer carefully. Research the company before the interview.",example:"A: ¿Por qué quiere este puesto?\nB: Porque admiro los valores de su empresa.\nA: ¿Qué sabe sobre nosotros?\nB: Sé que son líderes en innovación tecnológica.",exampleSrc:"A: Why do you want this position?\nB: Because I admire your company's values.\nA: What do you know about us?\nB: I know you are leaders in technological innovation.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Mis fortalezas son",src:"My strengths are",pos:"intj",gender:null,phonetic:"mees for-ta-LEH-sas son",note:"La fortaleza = strength. Always give specific examples after naming your strengths.",example:"A: ¿Cuáles son sus fortalezas?\nB: Mis fortalezas son la organización y la comunicación.\nA: ¿Puede darme un ejemplo concreto?\nB: En mi último proyecto, coordiné un equipo de diez personas.",exampleSrc:"A: What are your strengths?\nB: My strengths are organization and communication.\nA: Can you give me a concrete example?\nB: In my last project, I coordinated a team of ten people.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Me considero una persona",src:"I consider myself a person who",pos:"intj",gender:null,phonetic:"meh kon-SEE-deh-ro OO-na per-SO-na",note:"A humble yet confident way to describe yourself in interviews.",example:"A: ¿Cómo se describiría usted?\nB: Me considero una persona responsable y proactiva.\nA: ¿Cómo maneja el estrés?\nB: Me considero una persona que trabaja bien bajo presión.",exampleSrc:"A: How would you describe yourself?\nB: I consider myself a responsible and proactive person.\nA: How do you handle stress?\nB: I consider myself a person who works well under pressure.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Tengo habilidades en",src:"I have skills in",pos:"noun",gender:null,phonetic:"TEN-go a-bee-lee-DA-des en",note:"La habilidad = skill/ability. Plural: las habilidades.",example:"A: ¿Qué habilidades tiene para este puesto?\nB: Tengo habilidades en gestión de proyectos y análisis de datos.\nA: ¿Domina algún programa informático?\nB: Sí, tengo habilidades en Excel y Python.",exampleSrc:"A: What skills do you have for this position?\nB: I have skills in project management and data analysis.\nA: Do you master any computer programs?\nB: Yes, I have skills in Excel and Python.",funFact:"Spanish nouns are either masculine or feminine. The ending usually gives it away."},
        {type:"teach",trg:"Mi área de mejora es",src:"My area for improvement is",pos:"intj",gender:null,phonetic:"mee AH-reh-a deh meh-HO-ra es",note:"A professional way to discuss weaknesses. Always mention what you are doing to improve.",example:"A: ¿Cuál es su mayor debilidad?\nB: Mi área de mejora es la paciencia con los procesos lentos.\nA: ¿Qué hace para mejorar?\nB: Estoy aprendiendo técnicas de gestión del tiempo.",exampleSrc:"A: What is your biggest weakness?\nB: My area for improvement is patience with slow processes.\nA: What do you do to improve?\nB: I am learning time management techniques.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Interview etiquette in Spanish",text:"In Spanish-speaking countries:\n\nUse usted consistently throughout.\nArrive 10 minutes early.\nShake hands firmly but briefly.\nMaintain eye contact.\nAlways prepare questions to ask the interviewer.\nSay 'Muchas gracias por su tiempo' when leaving.",icon:"💡"},
        {type:"mc",q:"El entrevistador dice: '___.' Es la primera pregunta clásica.",opts:["Hábleme de usted","¿Cuánto quiere ganar?","¿Tiene coche?","¿Dónde vive?"],ans:"Hábleme de usted",hint:"The universal opening question where you present yourself."},
        {type:"mc",q:"Para describir tus puntos fuertes, dices: 'Mis ___ son la creatividad y el liderazgo.'",opts:["debilidades","fortalezas","problemas","experiencias"],ans:"fortalezas",hint:"The word that means 'strengths' in a professional context."},
        {type:"fb",opts:["considero","llamo","presento","siento"],hint:"The verb that means 'I consider' for self-description.",s:"Me {1} una persona organizada y puntual.",a:"considero"},
        {type:"mc",q:"When asked about weaknesses, the professional approach is:",opts:["Decir que no tienes debilidades","Criticar a tu jefe anterior","Hablar de tu área de mejora y qué haces para mejorar","Cambiar de tema rápidamente"],ans:"Hablar de tu área de mejora y qué haces para mejorar",hint:"Name the a___ and show you are actively working on it."},
        {type:"fb",opts:["habilidades","problemas","reuniones","entrevistas"],hint:"The plural noun meaning skills or abilities.",s:"Tengo {1} en comunicación y trabajo en equipo.",a:"habilidades"},
        {type:"match",pairs:[
          {trg:"Hábleme de usted",src:"Tell me about yourself"},
          {trg:"Mis fortalezas",src:"My strengths"},
          {trg:"Mi área de mejora",src:"My area for improvement"},
          {trg:"Me considero",src:"I consider myself"},
          {trg:"Tengo habilidades en",src:"I have skills in"}
        ]},
        {type:"mc",q:"'¿___ quiere este puesto?' pregunta el entrevistador.",opts:["Cuándo","Dónde","Cómo","Por qué"],ans:"Por qué",hint:"The question word that asks for your motivation and reasons."},
        {type:"drag_fill",hint:"Self-description, strengths, and skills in an interview answer.",s:"{1} una persona responsable. Mis {2} son la comunicación y el liderazgo. Tengo {3} en gestión de equipos.",blanks:{"1":"Me considero","2":"fortalezas","3":"habilidades"},pool:["Me considero","fortalezas","habilidades","Me llamo","debilidades","problemas"]},
        {type:"mc",q:"At the end of an interview, you should say:",opts:["Muchas gracias por su tiempo","Chao, hasta luego","Bueno, me voy","¿Cuándo me pagan?"],ans:"Muchas gracias por su tiempo",hint:"Thank the interviewer formally for the time they dedicated to you."},
        {type:"fb",opts:["área","fortaleza","habilidad","entrevista"],hint:"The word meaning 'area' that precedes 'for improvement'.",s:"Mi {1} de mejora es la gestión del tiempo.",a:"área"}
  ]},
  {id:"esp24l6",title:"La cultura laboral",icon:"🌍",xp:20,board:true,steps:[
        {type:"intro",title:"La cultura laboral",desc:"Discover how work culture differs across Spanish-speaking countries and navigate professional relationships.",goals:["Understand work schedules and customs","Navigate tú vs usted in the workplace","Discuss work-life balance in Spanish"]},
        {type:"teach",trg:"el horario de trabajo",src:"work schedule",pos:"noun",gender:"m",phonetic:"o-RA-ryo deh tra-BA-ho",note:"In Spain, el horario partido splits the day with a long lunch. Latin America often uses el horario corrido (continuous).",example:"A: ¿Cuál es tu horario de trabajo?\nB: Trabajo de nueve a seis con una hora para comer.\nA: ¿Es normal ese horario en España?\nB: Sí, muchas empresas tienen horario partido.",exampleSrc:"A: What is your work schedule?\nB: I work from nine to six with one hour for lunch.\nA: Is that schedule normal in Spain?\nB: Yes, many companies have a split schedule.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la jornada laboral",src:"the working day",pos:"noun",gender:"f",phonetic:"hor-NA-da la-bo-RAL",note:"Jornada intensiva = summer schedule with shorter hours. Common in Spain.",example:"A: ¿Cuántas horas dura la jornada laboral aquí?\nB: La jornada normal es de ocho horas.\nA: ¿Hay jornada intensiva en verano?\nB: Sí, en julio y agosto salimos a las tres.",exampleSrc:"A: How many hours does the working day last here?\nB: The normal day is eight hours.\nA: Is there an intensive schedule in summer?\nB: Yes, in July and August we leave at three.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"la sobremesa laboral",src:"post-meal chat at work",pos:"noun",gender:"f",phonetic:"so-breh-MEH-sa la-bo-RAL",note:"Sobremesa: the time spent talking after a meal. Valued for building relationships at work.",example:"A: ¿Tomamos un café después de comer?\nB: Sí, la sobremesa es mi momento favorito del día.\nA: Aquí todos se quedan charlando después de comer.\nB: Es una tradición importante en nuestra cultura laboral.",exampleSrc:"A: Shall we have a coffee after lunch?\nB: Yes, the post-meal chat is my favorite moment of the day.\nA: Here everyone stays chatting after eating.\nB: It is an important tradition in our work culture.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"tutear",src:"to use tú (informal 'you')",pos:"verb",gender:null,phonetic:"too-teh-AR",note:"In many modern offices, tutear is normal. But always wait for permission or follow others' lead.",example:"A: ¿En tu oficina se tutean todos?\nB: Sí, desde el primer día me dijeron que los tuteara.\nA: En mi empresa todavía usamos usted con los directivos.\nB: Depende mucho de la cultura de cada empresa.",exampleSrc:"A: In your office does everyone use tú with each other?\nB: Yes, from the first day they told me to use tú with them.\nA: In my company we still use usted with the managers.\nB: It depends a lot on each company's culture.",funFact:"A regular -ar verb, the largest Spanish verb group. Learn this pattern and you unlock hundreds of verbs."},
        {type:"teach",trg:"el ambiente laboral",src:"the work environment",pos:"noun",gender:"m",phonetic:"am-BYEN-teh la-bo-RAL",note:"Un buen ambiente laboral = a good work environment. Key for job satisfaction.",example:"A: ¿Cómo es el ambiente laboral en tu empresa?\nB: Es muy positivo. Hay buen compañerismo.\nA: ¿Hacen actividades fuera de la oficina?\nB: Sí, organizamos cenas de equipo cada mes.",exampleSrc:"A: What is the work environment like at your company?\nB: It is very positive. There is good camaraderie.\nA: Do you do activities outside the office?\nB: Yes, we organize team dinners every month.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"conciliar trabajo y vida personal",src:"to balance work and personal life",pos:"verb",gender:null,phonetic:"kon-see-LYAR tra-BA-ho ee VEE-da per-so-NAL",note:"Work-life balance is increasingly important in Spanish-speaking countries.",example:"A: ¿Es difícil conciliar trabajo y vida personal?\nB: A veces sí, sobre todo cuando hay mucho estrés.\nA: ¿Tu empresa ofrece teletrabajo?\nB: Sí, podemos trabajar desde casa dos días a la semana.",exampleSrc:"A: Is it difficult to balance work and personal life?\nB: Sometimes yes, especially when there is a lot of stress.\nA: Does your company offer remote work?\nB: Yes, we can work from home two days a week.",funFact:"Spanish verbs encode the subject in their ending, so pronouns are often dropped."},
        {type:"tip",title:"Tú vs usted in the workplace",text:"Rules vary by country and company:\n\nSpain: Many offices tutean everyone, even the boss.\nMexico: More formal. Usted with superiors is common.\nArgentina: Vos replaces tú in most contexts.\nColombia: Very formal. Usted is widely used, even among friends.\n\nWhen in doubt, start with usted and wait for the other person to suggest tú.",icon:"💡"},
        {type:"mc",q:"En España, muchas empresas tienen 'horario partido'. Esto significa:",opts:["Dividir el día con una pausa larga para comer","Trabajar sin pausa","Trabajar solo por la mañana","No tener horario fijo"],ans:"Dividir el día con una pausa larga para comer",hint:"The split schedule breaks the day into two halves around a long meal break."},
        {type:"mc",q:"'La ___ es mi momento favorito. Me gusta charlar con los compañeros después de comer.'",opts:["reunión","sobremesa","entrevista","jornada"],ans:"sobremesa",hint:"The post-meal social time that is a cherished tradition."},
        {type:"fb",opts:["tutean","hablan","escriben","llaman"],hint:"The verb that means to address someone using the informal 'you'.",s:"En nuestra oficina todos se {1}. Nadie usa usted.",a:"tutean"},
        {type:"mc",q:"¿Qué es la 'jornada intensiva'?",opts:["Trabajar más horas de lo normal","Una reunión muy larga","Un horario más corto, común en verano","Un tipo de contrato laboral"],ans:"Un horario más corto, común en verano",hint:"A schedule adjustment made during the hottest months."},
        {type:"match",pairs:[
          {trg:"el horario de trabajo",src:"work schedule"},
          {trg:"la sobremesa",src:"post-meal chat"},
          {trg:"tutear",src:"to use tú"},
          {trg:"el ambiente laboral",src:"work environment"},
          {trg:"conciliar",src:"to balance (work/life)"}
        ]},
        {type:"fb",opts:["conciliar","contratar","despedir","tutear"],hint:"The verb meaning to balance or reconcile two aspects of life.",s:"Es importante {1} el trabajo y la vida personal.",a:"conciliar"},
        {type:"mc",q:"In Colombia, when meeting a new colleague, you should probably:",opts:["Use tú immediately","Use vos always","Avoid any greeting","Start with usted until told otherwise"],ans:"Start with usted until told otherwise",hint:"Colombia tends toward more formal address in professional settings."},
        {type:"drag_fill",hint:"A positive workplace where everyone is on informal terms with flexible scheduling.",s:"El {1} laboral es bueno. Todos se {2} y el {3} de trabajo es flexible.",blanks:{"1":"ambiente","2":"tutean","3":"horario"},pool:["ambiente","tutean","horario","sueldo","despiden","puesto"]},
        {type:"mc",q:"'Mi empresa ofrece teletrabajo para ___ trabajo y vida personal.'",opts:["conciliar","contratar","despedir","tutear"],ans:"conciliar",hint:"The verb that means to balance or harmonize two things."},
        {type:"mc",q:"'En España, la ___ después del almuerzo es una tradición muy valorada en las oficinas.'",opts:["entrevista","sobremesa","jornada","conciliación"],ans:"sobremesa",hint:"The social time spent chatting after eating together."}
  ]},
  {id:"esp24l7",title:"Opiniones profesionales",icon:"💬",xp:20,board:true,steps:[
        {type:"intro",title:"Opiniones profesionales",desc:"Learn to express and discuss professional opinions with confidence and nuance.",goals:["Express opinions formally and informally","Agree and disagree professionally","Use opinion markers in discussions"]},
        {type:"teach",trg:"En mi opinión",src:"In my opinion",pos:"intj",gender:null,phonetic:"en mee o-pee-NYON",note:"Universal opinion marker. Works in both formal and informal contexts.",example:"A: ¿Qué piensas del nuevo proyecto?\nB: En mi opinión, necesitamos más tiempo para planificarlo.\nA: ¿Cuánto tiempo más?\nB: En mi opinión, al menos dos semanas adicionales.",exampleSrc:"A: What do you think about the new project?\nB: In my opinion, we need more time to plan it.\nA: How much more time?\nB: In my opinion, at least two additional weeks.",funFact:"Cognate with English 'in my opinion'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"Considero que",src:"I consider that / I believe that",pos:"intj",gender:null,phonetic:"kon-SEE-deh-ro keh",note:"More formal than 'creo que'. Ideal for meetings and professional discussions.",example:"A: ¿Cómo ve la situación del mercado?\nB: Considero que hay oportunidades interesantes.\nA: ¿En qué sector específicamente?\nB: Considero que el sector tecnológico tiene más potencial.",exampleSrc:"A: How do you see the market situation?\nB: I consider that there are interesting opportunities.\nA: In which sector specifically?\nB: I consider that the tech sector has the most potential.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Desde mi punto de vista",src:"From my point of view",pos:"intj",gender:null,phonetic:"DES-deh mee POON-to deh VEES-ta",note:"Slightly more formal than 'en mi opinión'. Emphasizes personal perspective.",example:"A: ¿Debemos cambiar la estrategia?\nB: Desde mi punto de vista, sí.\nA: ¿Por qué lo cree?\nB: Desde mi punto de vista, los resultados actuales no son suficientes.",exampleSrc:"A: Should we change the strategy?\nB: From my point of view, yes.\nA: Why do you think so?\nB: From my point of view, the current results are not sufficient.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Estoy de acuerdo",src:"I agree",pos:"intj",gender:null,phonetic:"es-TOY deh a-KWER-do",note:"Estar de acuerdo con = to agree with. Estoy totalmente de acuerdo = I completely agree.",example:"A: Creo que necesitamos más personal.\nB: Estoy de acuerdo. No podemos seguir así.\nA: ¿Hablo con recursos humanos?\nB: Sí, estoy totalmente de acuerdo.",exampleSrc:"A: I think we need more staff.\nB: I agree. We cannot continue like this.\nA: Shall I talk to human resources?\nB: Yes, I totally agree.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"No estoy de acuerdo",src:"I disagree",pos:"intj",gender:null,phonetic:"no es-TOY deh a-KWER-do",note:"Direct but professional. Softer: 'No estoy del todo de acuerdo' (I don't entirely agree).",example:"A: Propongo reducir el presupuesto un veinte por ciento.\nB: No estoy de acuerdo. Eso afectaría la calidad.\nA: ¿Qué alternativa sugiere?\nB: Considero que debemos buscar nuevos clientes primero.",exampleSrc:"A: I propose reducing the budget by twenty percent.\nB: I disagree. That would affect the quality.\nA: What alternative do you suggest?\nB: I consider that we should look for new clients first.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Respeto su opinión, pero",src:"I respect your opinion, but",pos:"intj",gender:null,phonetic:"res-PEH-to soo o-pee-NYON PEH-ro",note:"A polite way to disagree. Shows respect before presenting your counterargument.",example:"A: El teletrabajo reduce la productividad.\nB: Respeto su opinión, pero los datos muestran lo contrario.\nA: ¿Qué datos tiene?\nB: Según un estudio reciente, la productividad aumentó un quince por ciento.",exampleSrc:"A: Remote work reduces productivity.\nB: I respect your opinion, but the data shows the opposite.\nA: What data do you have?\nB: According to a recent study, productivity increased by fifteen percent.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Softening disagreement",text:"Professional Spanish values indirect disagreement:\n\nDirect: No estoy de acuerdo.\nSofter: No estoy del todo de acuerdo.\nPolite: Respeto su opinión, pero...\nDiplomatic: Entiendo su punto, sin embargo...\n\nThe more formal the context, the softer your disagreement should be.",icon:"💡"},
        {type:"mc",q:"En una reunión formal, la forma más apropiada de dar tu opinión es:",opts:["Considero que deberíamos analizar los datos","Yo digo que no","Eso es tonto","No me gusta"],ans:"Considero que deberíamos analizar los datos",hint:"The option that uses a formal opinion marker with a constructive suggestion."},
        {type:"mc",q:"Tu colega propone algo con lo que estás de acuerdo. Dices:",opts:["No estoy de acuerdo","Estoy totalmente de acuerdo","Respeto su opinión, pero no","Desde mi punto de vista, no"],ans:"Estoy totalmente de acuerdo",hint:"The phrase that expresses full agreement with emphasis."},
        {type:"fb",opts:["Desde","En","Por","Con"],hint:"This preposition starts the phrase meaning 'from my point of view'.",s:"{1} mi punto de vista, el proyecto necesita más recursos.",a:"Desde"},
        {type:"mc",q:"To politely disagree with a superior, you say:",opts:["Eso es incorrecto","No estoy de acuerdo y punto","Respeto su opinión, pero los datos indican otra cosa","Está equivocado"],ans:"Respeto su opinión, pero los datos indican otra cosa",hint:"Show respect first, then present your evidence."},
        {type:"fb",opts:["acuerdo","parte","lado","opinión"],hint:"The noun that completes 'estar de ___' to express agreement or disagreement.",s:"No estoy de {1} con esa propuesta.",a:"acuerdo"},
        {type:"match",pairs:[
          {trg:"En mi opinión",src:"In my opinion"},
          {trg:"Considero que",src:"I consider that"},
          {trg:"Estoy de acuerdo",src:"I agree"},
          {trg:"No estoy de acuerdo",src:"I disagree"},
          {trg:"Respeto su opinión",src:"I respect your opinion"}
        ]},
        {type:"mc",q:"'___ que deberíamos invertir más en formación para el equipo.'",opts:["Opino de","Acuerdo","Respeto","Considero"],ans:"Considero",hint:"The formal verb meaning 'I consider' or 'I believe'."},
        {type:"drag_fill",hint:"An opinion marker, agreement expression, and a formal belief statement.",s:"{1} mi opinión, el plan es bueno. Estoy {2} acuerdo, pero {3} que necesitamos más datos.",blanks:{"1":"En","2":"de","3":"considero"},pool:["En","de","considero","Desde","del","creo"]},
        {type:"mc",q:"Which phrase is the MOST diplomatic way to disagree?",opts:["Entiendo su punto, sin embargo pienso diferente","No estoy de acuerdo","No, eso está mal","Tiene razón, pero no"],ans:"Entiendo su punto, sin embargo pienso diferente",hint:"Acknowledge the other person's view before presenting your own."},
        {type:"fb",opts:["acuerdo","opinión","vista","punto"],hint:"The noun that completes a softened disagreement expression.",s:"No estoy del todo de {1} con su propuesta.",a:"acuerdo"}
  ]},
  {id:"esp24l8",title:"Repaso: El mundo laboral",icon:"🎯",xp:25,board:true,steps:[
        {type:"intro",title:"Repaso: El mundo laboral",desc:"Review all the work vocabulary, formal register, and professional communication from this unit.",goals:["Use work vocabulary accurately","Write formal phrases from memory","Navigate interviews and professional opinions"]},
        {type:"mc",q:"'Tengo una ___ con mi jefe a las tres para hablar del proyecto.'",opts:["reunión","empresa","experiencia","oficina"],ans:"reunión",hint:"A scheduled gathering to discuss work matters."},
        {type:"mc",q:"The formal opening of a business letter is:",opts:["Hola, ¿qué tal?","Estimado señor García","Querido amigo","Oye, te escribo"],ans:"Estimado señor García",hint:"The standard formal greeting that precedes the recipient's name."},
        {type:"fb",opts:["agradezco","escribo","envío","presento"],hint:"The formal verb meaning 'I thank you'.",s:"Le {1} su rápida respuesta a mi solicitud.",a:"agradezco"},
        {type:"mc",q:"En una entrevista, te preguntan tus puntos fuertes. Respondes:",opts:["No tengo fortalezas","Mi sueldo es bajo","Mis fortalezas son la organización y el liderazgo","La empresa es pequeña"],ans:"Mis fortalezas son la organización y el liderazgo",hint:"Name specific professional strengths with the correct vocabulary."},
        {type:"drag_fill",hint:"Formal opening for a woman, stating purpose, and naming the position.",s:"{1} señora López, le {2} para expresar mi interés en el {3} de gerente.",blanks:{"1":"Estimada","2":"escribo","3":"puesto"},pool:["Estimada","escribo","puesto","Estimado","agradezco","empleo"]},
        {type:"mc",q:"'La ___ laboral es importante para la salud mental.' Completa:",opts:["sobremesa","reunión","entrevista","conciliación"],ans:"conciliación",hint:"The noun form of 'conciliar', meaning work-life balance."},
        {type:"fb",opts:["experiencia","reunión","entrevista","oficina"],hint:"What you accumulate over years of working in a field.",s:"Cuento con {1} en marketing digital y análisis de datos.",a:"experiencia"},
        {type:"mc",q:"Para expresar desacuerdo profesionalmente: 'Respeto su opinión, ___ creo que hay alternativas.'",opts:["pero","y","porque","cuando"],ans:"pero",hint:"The conjunction that introduces a contrasting view after showing respect."},
        {type:"match",pairs:[{trg:"el sueldo",src:"the salary"},{trg:"contratar",src:"to hire"},{trg:"despedir",src:"to fire"},{trg:"Atentamente",src:"Sincerely"},{trg:"Hábleme de usted",src:"Tell me about yourself"}]},
        {type:"mc",q:"Completa la carta: '___ mi currículum para su consideración.'",opts:["Envío","Adjunto","Escribo","Pongo"],ans:"Adjunto",hint:"The formal verb used to attach documents in professional correspondence."},
        {type:"fb",opts:["considero","llamo","presento","encuentro"],hint:"The reflexive verb meaning 'I consider myself'.",s:"Me {1} una persona responsable y trabajadora.",a:"considero"},
        {type:"mc",q:"In many Spanish offices, 'tutear' means:",opts:["Hablar en inglés","Usar usted con todos","Usar tú de manera informal","No hablar con nadie"],ans:"Usar tú de manera informal",hint:"The verb derived from the pronoun tú."},
        {type:"drag_fill",hint:"Strengths, a formal belief, and contributing value.",s:"Mis {1} son la comunicación y el trabajo en equipo. {2} que puedo {3} valor a su empresa.",blanks:{"1":"fortalezas","2":"Considero","3":"aportar"},pool:["fortalezas","Considero","aportar","debilidades","Creo","buscar"]},
        {type:"mc",q:"La 'jornada intensiva' en España se aplica normalmente en:",opts:["Navidad","Todo el año","Semana Santa","Verano (julio y agosto)"],ans:"Verano (julio y agosto)",hint:"The shorter schedule applies during the hottest months of the year."},
        {type:"fb",opts:["espera","vista","mano","parte"],hint:"The closing phrase that means 'I await' your reply.",s:"Quedo a la {1} de su respuesta. Atentamente, Carlos Ruiz.",a:"espera"},
        {type:"mc",q:"Which complete sentence could close a cover letter?",opts:["Adjunto mi currículum. Quedo a su disposición. Atentamente, Ana Martín.","Chao, nos vemos mañana","Bueno, adiós. Te escribo luego.","Gracias, hasta la vista."],ans:"Adjunto mi currículum. Quedo a su disposición. Atentamente, Ana Martín.",hint:"The option with all the formal elements: attachment, availability, closing, and signature."},
        {type:"drag_fill",hint:"A perspective marker, disagreement, and a formal belief in a professional discussion.",s:"{1} mi punto de vista, necesitamos cambiar la estrategia. No estoy de {2} con el plan actual. {3} que hay mejores opciones.",blanks:{"1":"Desde","2":"acuerdo","3":"Considero"},pool:["Desde","acuerdo","Considero","En","parte","Creo"]},
        {type:"mc",q:"You want to ask a colleague about their work environment. You say:",opts:["¿Cómo es el sueldo?","¿Cómo es el ambiente laboral?","¿Cómo es la carta de presentación?","¿Cómo es el currículum?"],ans:"¿Cómo es el ambiente laboral?",hint:"The phrase asking about the overall feeling and culture of the workplace."}
  ]},
  {id:"esp24l8b",title:"En la Oficina: Vocabulario",icon:"🏢",xp:20,board:true,steps:[
        {type:"intro",title:"Office Vocabulary",desc:"Palabras esenciales para el entorno laboral.\nLearn key workplace and office vocabulary in Spanish.",goals:["Learn 12 workplace words with articles","Practice office vocabulary in dialogues","Use work vocabulary in context"]},
        {type:"teach",trg:"la reunión",src:"the meeting",pos:"noun",gender:"f",note:"la reunión (f.)\nAlso: la junta (Latin America).",example:"A: ¿Tienes una reunión hoy?\nB: Sí, a las dos con el equipo.\nA: ¿En qué sala?\nB: En la sala de conferencias del tercer piso.",exampleSrc:"A: Do you have a meeting today?\nB: Yes, at two with the team.\nA: In which room?\nB: In the conference room on the third floor.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el informe",src:"the report",pos:"noun",gender:"m",note:"el informe (m.)\nAlso: el reporte (Latin America).",example:"A: ¿Ya terminaste el informe?\nB: Casi. Me faltan los datos del mes.\nA: El jefe lo necesita para mañana.\nB: Lo tendré listo esta noche.",exampleSrc:"A: Did you finish the report yet?\nB: Almost. I'm missing this month's data.\nA: The boss needs it by tomorrow.\nB: I'll have it ready tonight.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el correo electrónico",src:"the email",pos:"noun",gender:"m",note:"el correo electrónico (m.)\nShort form: el correo, el email.",example:"A: ¿Recibiste mi correo electrónico?\nB: No, no me llegó nada.\nA: Qué raro. Te lo reenvío ahora.\nB: Gracias, reviso en cinco minutos.",exampleSrc:"A: Did you receive my email?\nB: No, I didn't get anything.\nA: That's strange. I'll resend it now.\nB: Thanks, I'll check in five minutes.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el plazo",src:"the deadline",pos:"noun",gender:"m",note:"el plazo (m.)\nAlso: la fecha límite.",example:"A: ¿Cuál es el plazo para el proyecto?\nB: El viernes a las cinco.\nA: Necesitamos más tiempo.\nB: Podemos pedir una extensión al director.",exampleSrc:"A: What's the deadline for the project?\nB: Friday at five.\nA: We need more time.\nB: We can ask the director for an extension.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el proyecto",src:"the project",pos:"noun",gender:"m",note:"el proyecto (m.)\nCommon: proyecto de investigación (research project).",example:"A: ¿Cómo va el proyecto nuevo?\nB: Bien, pero hay mucho trabajo.\nA: ¿Necesitas ayuda?\nB: Sí, busco a alguien del departamento de ventas.",exampleSrc:"A: How's the new project going?\nB: Good, but there's a lot of work.\nA: Do you need help?\nB: Yes, I'm looking for someone from sales.",funFact:"Cognate with English 'project'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el/la colega",src:"the colleague",pos:"intj",gender:null,note:"el colega / la colega\nSame form for both genders.\nAlso: el/la compañero/a de trabajo.",example:"A: Mi colega habla tres idiomas.\nB: ¡Qué útil para la empresa!\nA: Sí, trabaja con clientes internacionales.\nB: Me gustaría conocerlo.",exampleSrc:"A: My colleague speaks three languages.\nB: How useful for the company!\nA: Yes, he works with international clients.\nB: I'd like to meet him.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"el jefe / la jefa",src:"the boss",pos:"noun",gender:"m",note:"el jefe (m.) / la jefa (f.)\nAlso: el/la director/a, el/la gerente.",example:"A: ¿Quién es tu jefa?\nB: La señora García. Es muy exigente.\nA: ¿Es buena jefa?\nB: Sí, exigente pero justa.",exampleSrc:"A: Who is your boss?\nB: Ms. García. She's very demanding.\nA: Is she a good boss?\nB: Yes, demanding but fair.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"el departamento",src:"the department",pos:"noun",gender:"m",note:"el departamento (m.)\nCommon: departamento de ventas, de recursos humanos.",example:"A: ¿En qué departamento trabajas?\nB: En el departamento de marketing.\nA: ¿Cuántas personas hay?\nB: Somos diez en total.",exampleSrc:"A: Which department do you work in?\nB: In the marketing department.\nA: How many people are there?\nB: There are ten of us in total.",funFact:"Cognate with English 'department'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"la solicitud",src:"the application",pos:"noun",gender:"f",note:"la solicitud (f.)\nSolicitar = to apply for.\nAlso: la candidatura.",example:"A: Envié la solicitud ayer.\nB: ¿Para qué puesto?\nA: Para el puesto de analista.\nB: Espero que te llamen pronto.",exampleSrc:"A: I sent the application yesterday.\nB: For which position?\nA: For the analyst position.\nB: I hope they call you soon.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"el sueldo",src:"the salary",pos:"noun",gender:"m",note:"el sueldo (m.)\nAlso: el salario.\nun aumento = a raise.",example:"A: ¿Estás contento con tu sueldo?\nB: Más o menos. Quiero pedir un aumento.\nA: ¿Cuándo hablarás con tu jefe?\nB: La semana que viene.",exampleSrc:"A: Are you happy with your salary?\nB: More or less. I want to ask for a raise.\nA: When will you talk to your boss?\nB: Next week.",funFact:"Masculine noun. Spanish words ending in -o are usually masculine."},
        {type:"teach",trg:"la oficina",src:"the office",pos:"noun",gender:"f",note:"la oficina (f.)\nel escritorio = desk.\nla sala de reuniones = meeting room.",example:"A: Nuestra oficina es muy moderna.\nB: ¿Tienen espacio para todos?\nA: Sí, cada persona tiene su escritorio.\nB: Qué bien. La mía es pequeña.",exampleSrc:"A: Our office is very modern.\nB: Do you have space for everyone?\nA: Yes, each person has their own desk.\nB: How nice. Mine is small.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"teach",trg:"la empresa",src:"the company",pos:"noun",gender:"f",note:"la empresa (f.)\nAlso: la compañía, la firma.\nel empleado = employee.",example:"A: ¿Tu empresa es grande?\nB: Sí, tiene más de 500 empleados.\nA: ¿En qué sector trabajan?\nB: En tecnología y servicios digitales.",exampleSrc:"A: Is your company big?\nB: Yes, it has more than 500 employees.\nA: What sector do you work in?\nB: In technology and digital services.",funFact:"Feminine noun. Spanish words ending in -a are usually feminine."},
        {type:"mc",q:"¿Cómo se dice 'meeting' en español?",opts:["la reunión","el informe","el plazo","la solicitud"],ans:"la reunión",hint:"Think about a group getting together."},
        {type:"mc",q:"Tu jefa necesita ___ antes del viernes. (the report)",opts:["el correo","el informe","el sueldo","la oficina"],ans:"el informe",hint:"A written document with data and analysis."},
        {type:"fb",opts:["correo electrónico","reunión","sueldo","oficina"],hint:"An electronic message you send from your computer.",s:"Envié un {1} a todos mis colegas.",a:["correo electrónico"]},
        {type:"mc",q:"¿Cuál es el sinónimo de 'la fecha límite'?",opts:["la empresa","el sueldo","el plazo","el departamento"],ans:"el plazo",hint:"The time by which something must be finished."},
        {type:"fb",opts:["colega","sueldo","reunión","plazo"],hint:"Someone who works with you at the same place.",s:"Mi {1} trabaja en el departamento de ventas.",a:["colega"]},
        {type:"match",pairs:[{trg:"la reunión",src:"meeting"},{trg:"el informe",src:"report"},{trg:"el sueldo",src:"salary"},{trg:"la solicitud",src:"application"},{trg:"la empresa",src:"company"}]},
        {type:"mc",q:"El director de la empresa pidió un ___ sobre las ventas.",opts:["correo","sueldo","colega","informe"],ans:"informe",hint:"A document summarizing business results."},
        {type:"fb",opts:["departamento","proyecto","plazo","informe"],hint:"A section within a company with its own team.",s:"Trabajo en el {1} de recursos humanos.",a:["departamento"]},
        {type:"mc",q:"Mi hermana acaba de enviar su ___ para un nuevo trabajo.",opts:["solicitud","reunión","oficina","departamento"],ans:"solicitud",hint:"What you send when you want to be considered for a job."},
        {type:"match",pairs:[{trg:"el plazo",src:"deadline"},{trg:"el proyecto",src:"project"},{trg:"el jefe",src:"boss"},{trg:"la oficina",src:"office"},{trg:"el correo electrónico",src:"email"}]},
        {type:"mc",q:"Necesitamos terminar el ___ antes del lunes.",opts:["sueldo","proyecto","colega","departamento"],ans:"proyecto",hint:"A planned piece of work with a specific goal."},
        {type:"fb",opts:["empresa","oficina","reunión","solicitud"],hint:"The organization where people work together.",s:"La {1} tiene más de 200 empleados en tres países.",a:["empresa"]}
  ]},
  {id:"espNl_burocr",title:"La burocracia española",icon:"🏛️",xp:15,board:true,steps:[
    {type:"intro",title:"Handling Administrative Situations",desc:"Learn vocabulary for Spanish bureaucracy: the NIE, DNI, official documents, and how to navigate el ayuntamiento. Essential for living or working in Spain and tested on the DELE B1.",goals:["Navigate el ayuntamiento and official offices","Request and renew official documents","Use polite administrative Spanish"]},
    {type:"teach",trg:"el NIE",src:"the foreigner identification number",pos:"noun",gender:"m",note:"Número de Identidad de Extranjero. Required for any foreigner living, working, or buying property in Spain.\nAssigned by the police (Policía Nacional).",example:"A: Necesito abrir una cuenta bancaria.\nB: ¿Tienes el NIE?\nA: Todavía no. ¿Dónde lo pido?\nB: En la comisaría de la Policía Nacional.",exampleSrc:"A: I need to open a bank account.\nB: Do you have the NIE?\nA: Not yet. Where do I apply for it?\nB: At the National Police station.",funFact:"The NIE is the key to adult life in Spain: you need it to sign a rental contract, start a job, or pay taxes. Foreigners call the process of getting one 'the NIE ordeal.'"},
    {type:"teach",trg:"el DNI",src:"the national ID card",pos:"noun",gender:"m",note:"Documento Nacional de Identidad. Every Spanish citizen must have one from age 14.\nUsed instead of a passport for travel within the EU.",example:"A: ¿Tienes el pasaporte?\nB: No, pero tengo el DNI. Vale para viajar a Francia.\nA: ¿Y para abrir una cuenta?\nB: Sí, el DNI es suficiente.",exampleSrc:"A: Do you have your passport?\nB: No, but I have my national ID. It works for travelling to France.\nA: And for opening an account?\nB: Yes, the national ID is sufficient.",funFact:"Spain digitized its DNI in 2006, adding a chip with a digital signature. Citizens can sign documents electronically with their DNI 3.0."},
    {type:"teach",trg:"el documento",src:"the document",pos:"noun",gender:"m",note:"General term for any official paper. Los documentos = the documents.\nDocumentar = to document. Documentación = documentation.",example:"A: ¿Tienes los documentos?\nB: Sí, los tengo todos.\nA: ¿El pasaporte también?\nB: Sí, todo está en la carpeta.",exampleSrc:"A: Do you have the documents?\nB: Yes, I have all of them.\nA: The passport too?\nB: Yes, everything is in the folder.",funFact:"In Spain, 'los papeles' (papers) is informal slang for any official documents. 'Tener los papeles en regla' means to have all your paperwork in order."},
    {type:"teach",trg:"el formulario",src:"the form",pos:"noun",gender:"m",note:"A form to be filled out. Rellenar un formulario = to fill in a form.\nEl formulario de solicitud = the application form.",example:"A: ¿Qué tengo que hacer primero?\nB: Tienes que rellenar este formulario.\nA: ¿Con bolígrafo o con ordenador?\nB: Con bolígrafo, en letras mayúsculas.",exampleSrc:"A: What do I need to do first?\nB: You need to fill in this form.\nA: With a pen or on a computer?\nB: With a pen, in capital letters.",funFact:"Spanish bureaucracy is famous for its love of paper forms. The word 'papeleo' (paperwork) is used humorously to describe the mountain of forms required for even simple tasks."},
    {type:"teach",trg:"el trámite",src:"the administrative procedure / paperwork step",pos:"noun",gender:"m",note:"A single step in a bureaucratic process. Los trámites = the procedures (plural).\nHacer un trámite = to carry out a procedure.",example:"A: ¿Cuántos trámites hay que hacer para el NIE?\nB: Varios. Primero pides la cita, luego traes los documentos.\nA: ¿Y cuánto tiempo tarda?\nB: Depende de la oficina, entre dos semanas y dos meses.",exampleSrc:"A: How many steps are there to get the NIE?\nB: Several. First you book the appointment, then you bring the documents.\nA: And how long does it take?\nB: It depends on the office, between two weeks and two months.",funFact:"'Trámites' is one of the most used words by expats in Spain. There is even a Spanish proverb: 'Vuelva usted mañana' (Come back tomorrow), the title of a satirical 19th-century essay about bureaucratic delays."},
    {type:"teach",trg:"la ventanilla",src:"the service window / counter",pos:"noun",gender:"f",note:"A small opening at a service desk in offices, banks, or post offices.\nAtendido en ventanilla = served at the counter.",example:"A: ¿Dónde presento el formulario?\nB: En la ventanilla número tres.\nA: ¿Hay mucha cola?\nB: Sí, hay que esperar unos veinte minutos.",exampleSrc:"A: Where do I hand in the form?\nB: At window number three.\nA: Is there a long queue?\nB: Yes, you will need to wait about twenty minutes.",funFact:"In Spain, many offices use a 'coger número' (take a number) system. You take a ticket and wait for your number to appear on a screen above the ventanilla."},
    {type:"teach",trg:"renovar",src:"to renew",pos:"verb",gender:null,note:"To renew a document, contract, or subscription. Irregular: stem change in some forms.\nRenuevo (I renew), renuevas, renueva, renovamos, renuevan.",example:"A: Necesito renovar el NIE.\nB: Tienes que ir al ayuntamiento.\nA: ¿Qué documentos necesito para renovar?\nB: El pasaporte y el formulario.",exampleSrc:"A: I need to renew my NIE.\nB: You need to go to the town hall.\nA: What documents do I need to renew it?\nB: The passport and the form.",funFact:"From Latin 'renovare' (to make new again). In Spain, official documents like the NIE and DNI expire every five or ten years and must be renovated in person."},
    {type:"tip",title:"Formal Register at the Ventanilla",text:"When speaking to officials at government offices, use usted (formal you):\n\nInformal: ¿Puedes ayudarme?\nFormal: ¿Podría ayudarme? (Could you help me?)\n\nKey polite phrases:\nNecesito renovar mi NIE. (I need to renew my NIE.)\n¿Qué documentos necesito? (What documents do I need?)\nMe gustaría pedir una cita. (I would like to book an appointment.)\n\nSpain uses the usted form consistently in any official or institutional context.",deepDive:"The subjunctive often appears in formal requests: 'Quisiera que me ayudara' (I would like you to help me). Using it signals you are comfortable with formal Spanish. At B1 level, the conditional alone (Podría, Quisiera) already sounds polished.",icon:"🏛️"},
    {type:"mc",q:"¿Cómo se llama en español el papel oficial que necesitas para hacer un trámite?",opts:["el documento","el correo electrónico","el proyecto","la reunión"],ans:"el documento",hint:"The general word for any official paper you carry to an office."},
    {type:"mc",q:"A foreigner living in Spain needs ___ to open a bank account.",opts:["el DNI","el NIE","el formulario","la ventanilla"],ans:"el NIE",hint:"This is the identification number specifically for non-Spanish residents."},
    {type:"mc",q:"¿Qué hace el empleado en la ventanilla?",opts:["Pide una cita","Rellena un formulario","Atiende al público","Renueva el pasaporte"],ans:"Atiende al público",hint:"A person working at the counter is there to serve the people waiting in the queue."},
    {type:"fb",opts:["renovar","rellenar","pedir","traer"],hint:"The verb meaning to make a document valid again for a new period.",s:"Mi pasaporte caduca pronto. Tengo que {1}lo.",a:"renovar"},
    {type:"mc",q:"¿Qué es un 'trámite'?",opts:["A type of form","A service window","An identity document","A step in an official procedure"],ans:"A step in an official procedure",hint:"The word describes the individual steps you must complete within a larger administrative process."},
    {type:"fb",opts:["formulario","documento","NIE","trámite"],hint:"The paper you fill in with your personal details when making an official request.",s:"Para pedir el NIE, primero hay que rellenar un {1}.",a:"formulario"},
    {type:"match",pairs:[{trg:"el NIE",src:"foreigner ID number"},{trg:"el DNI",src:"national ID card"},{trg:"el formulario",src:"the form"},{trg:"la ventanilla",src:"the service window"},{trg:"renovar",src:"to renew"},{trg:"el trámite",src:"an administrative step / procedure"}]}
  ]}
]};
